class Customer:
    def __init__(self, id, name, address, email, password):
        self.id = id
        self.name = name
        self.address = address
        self.email = email
        self.__password = password

    def __getpassword(self):
        return self.__password

    def __setpassword(self, new_password):
        if len(new_password) >= 8:
            self.__password = new_password
        else:
            print("Password must be at least 8 characters long")

def default_test():
    customer = Customer(id=1, name="Jane Doe", address="123 Main St", email="jane@example.com", password="securepwd")
    print(customer.id)
    print(customer.name)
    print(customer.address)
    print(customer.email)
    # The following line should not be able to access the password directly
    try:
        print(customer.__password)
    except AttributeError:
        print("Private attribute access is restricted")
